12	export type ExtractionLens = (typeof EXTRACTION_LENSES)[number];
13	
14	export type LensBudget = {
15	  enabled: boolean;
16	  maxLensesPerDocument: number;
17	  maxGroupsPerDocument: number;
18	  maxModelCallsPerDocument: number;
19	  maxEstimatedInputTokens: number;
20	};
