22	export type LensDispatchPlan = {
23	  selected: Array<{
24	    sourceGroupId: string;
25	    groupTitle: string;
26	    lens: ExtractionLens;
27	    estimatedInputTokens: number;
28	  }>;
29	  skipped: Array<{
30	    sourceGroupId?: string;
31	    groupTitle?: string;
32	    lens?: string;
33	    reason: string;
34	  }>;
35	  budget: LensBudget;
36	};
