38	const LENS_PRIORITY: ExtractionLens[] = [
39	  'handoffs',
40	  'exceptions_and_workarounds',
41	  'dependencies_and_sequence',
42	  'contradictions_and_tensions',
43	  'systems_and_data_entry',
44	  'ownership_and_roles',
45	  'definitions_and_acronyms',
46	  'customer_or_licensor_risk',
47	];
