49	function settingToBoolean(value: unknown, fallback: boolean): boolean {
50	  if (typeof value === 'boolean') return value;
51	  if (typeof value === 'string') return value === 'true' || value === '1';
52	  return fallback;
53	}
54	
55	function settingToInt(value: unknown, fallback: number): number {
56	  const parsed = typeof value === 'number' ? value : Number(value);
57	  return Number.isFinite(parsed) ? Math.floor(parsed) : fallback;
58	}
59	
60	function isExtractionLens(value: unknown): value is ExtractionLens {
61	  return typeof value === 'string' && (EXTRACTION_LENSES as readonly string[]).includes(value);
62	}
63	
64	function priority(lens: ExtractionLens): number {
65	  const index = LENS_PRIORITY.indexOf(lens);
66	  return index >= 0 ? index : LENS_PRIORITY.length;
67	}
