69	export async function loadLensBudget(db: OracleDb): Promise<LensBudget> {
70	  const rows = await db
71	    .select({ key: settings.key, value: settings.value })
72	    .from(settings)
73	    .where(
74	      inArray(settings.key, [
75	        'macro_lenses_enabled',
76	        'macro_max_lenses_per_document',
77	        'macro_max_lens_groups_per_document',
78	        'macro_max_lens_model_calls_per_document',
79	        'macro_max_lens_estimated_input_tokens',
80	      ]),
81	    );
82	  const values = new Map(rows.map((row) => [row.key, row.value]));
83	  return {
84	    enabled: settingToBoolean(values.get('macro_lenses_enabled'), true),
85	    maxLensesPerDocument: Math.max(0, settingToInt(values.get('macro_max_lenses_per_document'), 4)),
86	    maxGroupsPerDocument: Math.max(
87	      0,
88	      settingToInt(values.get('macro_max_lens_groups_per_document'), 8),
89	    ),
90	    maxModelCallsPerDocument: Math.max(
91	      0,
92	      settingToInt(values.get('macro_max_lens_model_calls_per_document'), 4),
93	    ),
94	    maxEstimatedInputTokens: Math.max(
95	      0,
96	      settingToInt(values.get('macro_max_lens_estimated_input_tokens'), 32_000),
97	    ),
98	  };
99	}
