101	export async function buildLensDispatchPlan(
102	  db: OracleDb,
103	  sourceOutlineId: string,
104	): Promise<LensDispatchPlan> {
105	  const budget = await loadLensBudget(db);
106	  const skipped: LensDispatchPlan['skipped'] = [];
107	  if (!budget.enabled)
108	    return { selected: [], skipped: [{ reason: 'macro_lenses_disabled' }], budget };
109	  if (budget.maxLensesPerDocument === 0 || budget.maxModelCallsPerDocument === 0) {
110	    return { selected: [], skipped: [{ reason: 'macro_lens_budget_zero' }], budget };
111	  }
112	
113	  const [outline] = await db
114	    .select({
115	      id: sourceOutlines.id,
116	      outlineJson: sourceOutlines.outlineJson,
117	      summary: sourceOutlines.summary,
118	    })
119	    .from(sourceOutlines)
120	    .where(eq(sourceOutlines.id, sourceOutlineId))
121	    .limit(1);
122	  if (!outline) return { selected: [], skipped: [{ reason: 'source_outline_not_found' }], budget };
123	
124	  const outlineJson = outline.outlineJson as Partial<SourceOutlineOutput>;
125	  const outlineLenses = (outlineJson.recommendedLenses ?? []).filter(isExtractionLens);
126	  const groups = await db
127	    .select({
128	      id: sourceGroups.id,
129	      title: sourceGroups.title,
130	      groupType: sourceGroups.groupType,
131	      metadataJson: sourceGroups.metadataJson,
132	      sortOrder: sourceGroups.sortOrder,
133	      textChars: sql<number>`COALESCE(SUM(length(${documentChunks.rawText})), 0)`,
134	    })
135	    .from(sourceGroups)
136	    .leftJoin(sourceGroupItems, eq(sourceGroupItems.sourceGroupId, sourceGroups.id))
137	    .leftJoin(documentChunks, eq(documentChunks.id, sourceGroupItems.documentChunkId))
138	    .where(eq(sourceGroups.sourceOutlineId, sourceOutlineId))
139	    .groupBy(sourceGroups.id)
140	    .orderBy(sourceGroups.sortOrder);
141	
142	  // COVERAGE-FIRST budgeting (2026-07-03). The old plan (a) hard-dropped groups
143	  // beyond maxGroupsPerDocument — which silently deleted the *terminal* workflow
144	  // stages (SKU creation, production, shipment) because they sort last — and (b)
145	  // sorted candidates lens-major, so the whole budget was spent running ONE lens
146	  // (handoffs) on the first few groups. Both together meant the endgame of a
147	  // swimlane diagram got zero lens coverage. See fix_enhancement.md §5 Bugs A/B/F.
148	  //
149	  // New model: every source group is a "round". Round 0 gives EVERY group its
150	  // single highest-priority lens before any group gets a second lens (round 1),
151	  // etc. Selection then walks rounds in order, so breadth-across-the-workflow
152	  // wins over depth-on-one-stage, and terminal stages are never dropped by sort
153	  // position. Cost stays bounded by maxModelCallsPerDocument and the token ceiling.
154	  const perGroup = groups.map((group) => {
155	    const metadata = group.metadataJson as { recommendedLenses?: unknown[] } | null;
156	    const groupLenses = (metadata?.recommendedLenses ?? []).filter(isExtractionLens);
157	    const lenses = [...new Set([...groupLenses, ...outlineLenses])].sort(
158	      (a, b) => priority(a) - priority(b),
159	    );
160	    // maxLensesPerDocument is a per-GROUP depth cap (its name is legacy; see the
161	    // note in loadLensBudget). It bounds how many lenses one stage can consume.
162	    const kept = lenses.slice(0, budget.maxLensesPerDocument);
163	    for (const lens of lenses.slice(budget.maxLensesPerDocument)) {
164	      skipped.push({
165	        sourceGroupId: group.id,
166	        groupTitle: group.title,
167	        lens,
168	        reason: `group_lens_depth_exceeds_${budget.maxLensesPerDocument}`,
169	      });
170	    }
171	    return {
172	      group,
173	      lenses: kept,
174	      estimatedInputTokens: Math.max(1, Math.ceil((Number(group.textChars) || 0) / 4) + 1500),
175	    };
176	  });
177	
178	  const maxRounds = Math.max(0, ...perGroup.map((g) => g.lenses.length));
179	  const candidates: Array<{
180	    sourceGroupId: string;
181	    groupTitle: string;
182	    groupSort: number;
183	    lens: ExtractionLens;
184	    estimatedInputTokens: number;
185	    round: number;
186	  }> = [];
187	  // Round-major, then group sort order: [g0.lens0, g1.lens0, … , g0.lens1, …].
188	  for (let round = 0; round < maxRounds; round += 1) {
189	    for (const g of perGroup) {
190	      const lens = g.lenses[round];
191	      if (!lens) continue;
192	      candidates.push({
193	        sourceGroupId: g.group.id,
194	        groupTitle: g.group.title,
195	        groupSort: g.group.sortOrder ?? 0,
196	        lens,
197	        estimatedInputTokens: g.estimatedInputTokens,
198	        round,
199	      });
200	    }
201	  }
202	
203	  const selected: LensDispatchPlan['selected'] = [];
204	  let tokenTotal = 0;
205	  const callLimit = budget.maxModelCallsPerDocument;
206	  for (const candidate of candidates) {
207	    if (selected.length >= callLimit) {
208	      skipped.push({ ...candidate, reason: `model_call_count_exceeds_${callLimit}` });
209	      continue;
210	    }
211	    if (tokenTotal + candidate.estimatedInputTokens > budget.maxEstimatedInputTokens) {
212	      skipped.push({
213	        ...candidate,
214	        reason: `estimated_input_tokens_exceed_${budget.maxEstimatedInputTokens}`,
215	      });
216	      continue;
217	    }
218	    selected.push({
219	      sourceGroupId: candidate.sourceGroupId,
220	      groupTitle: candidate.groupTitle,
221	      lens: candidate.lens,
222	      estimatedInputTokens: candidate.estimatedInputTokens,
223	    });
224	    tokenTotal += candidate.estimatedInputTokens;
225	  }
226	
227	  return { selected, skipped, budget };
228	}
