230	export async function documentHasCompletedLensBatch(args: {
231	  db: OracleDb;
232	  sourceHash: string;
233	}): Promise<boolean> {
234	  // Must include the TERMINAL status 'complete' (document-lens-extraction.ts
235	  // writes 'complete' as the final batch state). Omitting it made a fully
236	  // finished lens batch invisible to this guard, so a re-run re-extracted and
237	  // re-promoted duplicate lens claims (fix_enhancement.md §5 Bug C).
238	  const rows = await args.db.execute<{ id: string }>(sql`
239	    SELECT id
240	    FROM extraction_batches
241	    WHERE batch_type = 'document_lens_group'
242	      AND source_hash = ${args.sourceHash}
243	      AND status IN ('pending_model', 'model_complete', 'validation_complete', 'complete')
244	    LIMIT 1
245	  `);
246	  return [...rows].length > 0;
247	}
